const db = require('./db');
const stripe = require('stripe')(process.env.STRIPE_KEY);

class PaymentService {
  async processPayment(orderId, amount, customerId) {
    // RACE CONDITION: Check happens before lock
    // Thread 1 checks: payment not found
    // Thread 2 checks: payment not found
    // Both threads proceed to create payment

    const existingPayment = await db.query(
      'SELECT id FROM payments WHERE order_id = $1 AND status = \'completed\'',
      [orderId]
    );

    if (existingPayment.rows.length > 0) {
      return { success: false, error: 'Payment already processed' };
    }

    try {
      // Stripe charge happens here
      const charge = await stripe.charges.create({
        amount: Math.round(amount * 100),
        currency: 'usd',
        customer: customerId,
        metadata: { orderId }
      });

      // Payment recorded after charge - if server crashes here, orphaned charge
      await db.query(
        `INSERT INTO payments (order_id, stripe_id, amount, status, created_at)
         VALUES ($1, $2, $3, $4, NOW())`,
        [orderId, charge.id, amount, 'completed']
      );

      await db.query(
        'UPDATE orders SET status = \'paid\' WHERE id = $1',
        [orderId]
      );

      return { success: true, chargeId: charge.id };
    } catch (error) {
      // No rollback mechanism for failed Stripe charge
      console.error('Payment processing error:', error);
      throw error;
    }
  }

  async refundPayment(paymentId) {
    const payment = await db.query(
      'SELECT stripe_id, amount FROM payments WHERE id = $1',
      [paymentId]
    );

    if (payment.rows.length === 0) {
      throw new Error('Payment not found');
    }

    // No lock here either - concurrent refunds could happen
    const refund = await stripe.refunds.create({
      charge: payment.rows[0].stripe_id
    });

    await db.query(
      'UPDATE payments SET status = \'refunded\', refund_id = $1 WHERE id = $2',
      [refund.id, paymentId]
    );

    return refund;
  }

  async getPaymentStatus(orderId) {
    // Stale read: another transaction might be updating this
    const payment = await db.query(
      'SELECT status, stripe_id FROM payments WHERE order_id = $1',
      [orderId]
    );

    return payment.rows[0] || null;
  }
}

module.exports = PaymentService;

