const PaymentService = require('./payment-service');
const db = require('./db');
const stripe = require('stripe');

jest.mock('./db');
jest.mock('stripe');

describe('PaymentService Race Condition', () => {
  let paymentService;

  beforeEach(() => {
    paymentService = new PaymentService();
  });

  describe('processPayment', () => {
    it('should process payment successfully', async () => {
      db.query.mockResolvedValueOnce({ rows: [] }) // No existing payment
        .mockResolvedValueOnce({ rows: [{ id: 1 }] }) // Insert payment
        .mockResolvedValueOnce({ rows: [] }); // Update order

      stripe.charges.create.mockResolvedValue({
        id: 'ch_12345',
        amount: 10000
      });

      const result = await paymentService.processPayment(1, 100, 'cus_123');
      expect(result.success).toBe(true);
    });

    it('should prevent duplicate charges when same order processed simultaneously', async () => {
      // This test demonstrates the race condition
      // Two concurrent requests both see no payment, both charge Stripe

      // Simulating concurrent execution:
      const promise1 = paymentService.processPayment(1, 100, 'cus_123');
      const promise2 = paymentService.processPayment(1, 100, 'cus_123');

      // Both should succeed or one should fail
      // Currently BOTH succeed (BUG: duplicate charge)
      const results = await Promise.allSettled([promise1, promise2]);

      // This assertion will fail with current code
      // Exactly one should succeed
      const succeeded = results.filter(r => r.status === 'fulfilled' && r.value.success).length;
      expect(succeeded).toBe(1);
    });
  });

  describe('refundPayment', () => {
    it('should refund payment once', async () => {
      db.query.mockResolvedValue({
        rows: [{ stripe_id: 'ch_12345', amount: 100 }]
      });

      stripe.refunds.create.mockResolvedValue({
        id: 'ref_12345',
        charge: 'ch_12345'
      });

      await paymentService.refundPayment(1);
      expect(stripe.refunds.create).toHaveBeenCalledTimes(1);
    });

    it('should prevent double refunds on concurrent calls', async () => {
      db.query.mockResolvedValue({
        rows: [{ stripe_id: 'ch_12345', amount: 100 }]
      });

      stripe.refunds.create.mockResolvedValue({
        id: 'ref_12345'
      });

      // Concurrent refund calls
      const promise1 = paymentService.refundPayment(1);
      const promise2 = paymentService.refundPayment(1);

      const results = await Promise.allSettled([promise1, promise2]);

      // Should only succeed once
      const succeeded = results.filter(r => r.status === 'fulfilled').length;
      expect(succeeded).toBeLessThanOrEqual(1);
    });
  });
});
